import type { ScaleLinear, ScaleLogarithmic } from 'd3-scale';
import type GeoJSON from 'geojson';

import { _getCanvasColor as getCanvasColor } from '@dynatrace/strato-components/charts';

import { defineRadius } from './define-radius.js';
import type { Location } from '../../../types/location.js';
import { calculateHoveredColor } from '../../../utils/calculate-hovered-color.js';
import { defineColor } from '../../../utils/define-color.js';

type RadiusScale =
  | ScaleLinear<number, number>
  | ScaleLogarithmic<number, number>
  | ((value: number) => number);

export const parseBubbleDataToGeoJSON = <T extends Location>(
  data: T[],
  color: string | ((item: T) => string),
  radius: number | ((item: T) => number),
  scale: RadiusScale,
): GeoJSON.FeatureCollection => {
  return {
    type: 'FeatureCollection',
    features: data.map((feature) => {
      const { longitude, latitude, ...properties } = feature;
      const canvasColor = getCanvasColor(defineColor(color, feature));
      const hoveredColor = calculateHoveredColor(canvasColor);
      const scaledRadius = scale(defineRadius(radius, feature));

      return {
        type: 'Feature',
        properties: {
          data: feature,
          ...properties,
          __color: canvasColor,
          __hoveredColor: hoveredColor,
          __radius: scaledRadius,
          __lat: latitude,
        },
        geometry: { type: 'Point', coordinates: [longitude, latitude] },
      };
    }),
  };
};
